{"version":3,"sourceRoot":"","sources":["..\\components\\footer.scss","..\\base\\_mixins.scss"],"names":[],"mappings":"AAGI;EACI;;AAEJ;EACI;;ACFJ;EDKI;IACI","sourcesContent":["@use \"../base/mixins\" as m;\r\n\r\n.footer{\r\n    &__title{\r\n        color: #fff;\r\n    }\r\n    &__log{\r\n        height: 110px;\r\n    }\r\n    @include m.mobile{\r\n        &__logo{\r\n            height:90px;\r\n        }\r\n    }\r\n}","@use \"./vars\";\r\n\r\n// Adaptive base\r\n\r\n@mixin mobile{\r\n    @media (max-width: vars.$mobile) {\r\n        @content;\r\n    }\r\n}\r\n\r\n@mixin tablet{\r\n    @media (max-width: vars.$tablet) {\r\n        @content;\r\n    }\r\n}\r\n\r\n@mixin desktop{\r\n    @media (min-width: vars.$tablet) {\r\n        @content;\r\n    }\r\n}"]}IAAM;;EACN;IAAM;;EACN;IAAO;;;AAEX;EACI;IAAK;;EACL;IAAM;;EACN;IAAM;;EACN;IAAM;;EACN;IAAM;;EACN;IAAO;;;AAEX;EACI;IAAK;;EACL;IAAM;;EACN;IAAM;;EACN;IAAM;;EACN;IAAO;;;AAEX;EACI;IAAK;;EACL;IAAM;;EACN;IAAM;;EACN;IAAM;;EACN;IAAO;;;AAEX;EACI;IAAK;;EACL;IAAM;;EACN;IAAM;;EACN;IAAM;;EACN;IAAM;;EACN;IAAM;;EACN;IAAO;;;AAGX;EACI;EACA;;;AC9DJ;EACI;EACA;EACA;EACA,aCuCoB;EDtCpB;;AAEJ;EACI;EACA;EACA;EACA,aCiCmB;EDhCnB;;AAEJ;EACI;EACA;EACA;EACA,aC2BqB;ED1BrB;;AAEJ;EACI;EACA;EACA;EACA,aCqBiB;EDpBjB;;AAEJ;EACI;EACA;EACA;EACA,aCWoB;EDVpB;;AAEJ;EACI;EACA;EACA;EACA,aCGkB;EDFlB;;AAGJ;EACA,aCHiB;;;ADMjB;EACI,WChCI;;;ADkCR;EACI,WClCI;;;ADoCR;EACI,WCpCI;;;ADsCR;EACI,WCtCI;;;ADwCR;EACI,WCxCI;;;AD0CR;EACI,WCzCG;;;ACpBH;EFiEA;IACI;;EAEJ;IACI;;EAEJ;IACI;;EAEJ;IACI;;;AAKR;EACI,aC1Ca;ED2Cb,aCtCiB;EDuCjB;;;AAGJ;EACI,aChDa;EDiDb,aC9CmB;ED+CnB;;;AAEJ;EACI,aCrDa;EDsDb,aClDqB;EDmDrB;;;AAGJ;EACI,OCtGW;;;ADwGf;EACI,OCvGmB;;;AD0GvB;EACI;EACA;;;AAEJ;EACI;EACA;;;AAGJ;EACI,aC3Ea;ED4Eb;EACA,aC3EoB;ED4EpB;;;AAGJ;EACI,aClFa;EDmFb,aC9EiB;ED+EjB;;;AG7HJ;EACI;EACA;EACA;EACA;EAEA;EACA;;ADLA;ECFJ;IAUQ;;;;AAIR;EACI;EACA;EACA;EACA;EACA;;;AAEJ;EACI;EACA;EAiBA,YACI;EAEJ;EAEA;EACA,YACI;;;AAIR;EACI;EACA;EACA;EACA;EACA,YACI;EAIJ;;;AAEJ;EACI;;;AAGJ;EACI;EACA;EACA;;;ACtEJ;EAEI