   }\r\n    &--base{\r\n        display: flex;\r\n        gap: 2rem;\r\n        flex-direction: column;\r\n        padding: 2rem;\r\n        background-color: #ffffffbd;\r\n        border-radius: 2rem;\r\n        backdrop-filter: blur(12px);\r\n        border: 1px solid #ffffff;\r\n    }\r\n\r\n\r\n    &__icon{\r\n        width: 80px;\r\n        padding: 1.8rem;\r\n        background-color: vars.$lightColor;\r\n        border-radius: 1.5rem;\r\n    }\r\n\r\n    &__header{\r\n        display: grid;\r\n        position: relative;\r\n        gap: 1.2rem;\r\n        &--mini{\r\n            display: flex;\r\n            align-items: end;\r\n            gap: 1.2rem;\r\n            min-height: 8rem;\r\n            // padding-top: 3.2rem;\r\n\r\n            & > .service-card__price-tag,\r\n            & > .service-card__timeline-tag{\r\n                position: absolute;\r\n                right: 0;\r\n                text-align: right;\r\n            }\r\n\r\n            & > .service-card__price-tag{\r\n                top: 0;\r\n            }\r\n\r\n            & > .service-card__timeline-tag{\r\n                top: 2rem;\r\n                translate: none;\r\n            }\r\n\r\n            & > .service-card__title{\r\n                margin: 0;\r\n                font-size: vars.$h4Size;\r\n            }\r\n            \r\n\r\n        }\r\n    }\r\n    &__title{\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightMedium;\r\n    }\r\n    &__description{\r\n        line-height: 1.25;\r\n        @include m.desktop{\r\n            font-size: vars.$h6Size;\r\n        }\r\n    } \r\n    &__subtitle {\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightMedium;\r\n        &--grey {\r\n            min-height: 2lh;\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightMedium;\r\n            color: vars.$greyColor;\r\n        }\r\n    }\r\n    &__text{\r\n        // font-size: 1.6rem;\r\n        &--framed{\r\n            background-color: vars.$lightColor;\r\n            padding: 2rem;\r\n            border-radius: 1.5rem;\r\n            border: 1px solid #C5D9F5;\r\n            margin: 2rem 0;\r\n        }\r\n    }\r\n\r\n    &__details{\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 2rem;\r\n    }\r\n    &__steps{\r\n        display: flex;\r\n        flex-wrap: wrap;\r\n        list-style-position: inside;\r\n        & > li{\r\n            font-size: vars.$pSize;\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightSemibold;\r\n            background-color: vars.$lightColor;\r\n            color: vars.$primaryColor;\r\n            padding: 0.5rem 1.5rem;\r\n            border-radius: 0.8em;\r\n            margin-right: 1rem;\r\n            margin-top: 1rem;\r\n        }\r\n    }\r\n    &__features{\r\n        position: relative;\r\n        & > li {\r\n            margin: 0.5rem 0 0.5rem 1.3rem;\r\n            font-size: vars.$pSize;\r\n            color: vars.$greyColor;\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightMedium;\r\n            &::before{\r\n                transform: translateY(-20%);\r\n                left: 0;\r\n                position: absolute;\r\n                color: vars.$primaryColor;\r\n                font-size: 2.8rem;\r\n                content: \"â€˘\";\r\n            }\r\n        }\r\n    }\r\n    &__benefits{\r\n        display: flex;\r\n        flex-wrap: wrap;\r\n        & > li {\r\n            position: relative;\r\n            margin: 0.5rem 3rem;\r\n            font-size: vars.$pSize;\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightMedium;\r\n            &::before{\r\n                left: 0;\r\n                translate: -2.5rem -2px;\r\n                position: absolute;\r\n                content: url(/src/