: 6rem;\r\n            }\r\n            & > p { \r\n                margin-left: 0.5rem;\r\n                font-family: vars.$mainFontFamily;\r\n                font-weight: vars.$mainFontWeightSemibold;\r\n            }\r\n        }\r\n    }\r\n\r\n    @include m.tablet{\r\n        &__header{\r\n            &--mini{\r\n                display: grid;\r\n                grid-template-columns: 72px minmax(0, 1fr);\r\n                grid-template-areas:\r\n                    \"price price\"\r\n                    \"timeline timeline\"\r\n                    \"icon title\";\r\n                column-gap: 1.2rem;\r\n                row-gap: 0.6rem;\r\n                align-items: start;\r\n                min-height: auto;\r\n                padding-top: 0;\r\n\r\n                & > .service-card__price-tag,\r\n                & > .service-card__timeline-tag{\r\n                    position: static;\r\n                    right: auto;\r\n                    text-align: left;\r\n                    text-shadow: none;\r\n                    line-height: 1.25;\r\n                }\r\n\r\n                & > .service-card__price-tag{\r\n                    grid-area: price;\r\n                    justify-self: start;\r\n                }\r\n\r\n                & > .service-card__timeline-tag{\r\n                    grid-area: timeline;\r\n                    justify-self: start;\r\n                    top: auto;\r\n                    translate: none;\r\n                }\r\n\r\n                & > .service-card__icon{\r\n                    grid-area: icon;\r\n                }\r\n\r\n                & > .service-card__title{\r\n                    grid-area: title;\r\n                    align-self: center;\r\n                    min-width: 0;\r\n                }\r\n            }\r\n        }\r\n    }\r\n\r\n    @include m.mobile{\r\n        &__header{\r\n            &--mini{\r\n                display: grid;\r\n                grid-template-columns: 64px minmax(0, 1fr);\r\n                column-gap: 1rem;\r\n                row-gap: 0.4rem;\r\n\r\n                & > .service-card__price-tag,\r\n                & > .service-card__timeline-tag{\r\n                    font-size: 1.4rem;\r\n                }\r\n\r\n                & > .service-card__icon{\r\n                    width: 64px;\r\n                    padding: 1.4rem;\r\n                    border-radius: 1.2rem;\r\n                }\r\n\r\n                & > .service-card__title{\r\n                    line-height: 1.1;\r\n                }\r\n            }\r\n        }\r\n\r\n\r\n\r\n        &--glow{\r\n            gap: 1rem;\r\n            & > h4{\r\n                font-size: vars.$pSize;\r\n            }\r\n        }\r\n        &__details{\r\n            gap: 1rem;\r\n        }\r\n        &__steps, &__benefits{\r\n            & > li{\r\n                // margin: 0;\r\n                margin-top: 0.5rem;\r\n                font-size: vars.$pSize * 0.9;\r\n            }\r\n        }\r\n        &__description{\r\n            text-align: justify;\r\n        }\r\n        &__timeline-tag{\r\n            color:vars.$darkColor;\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightMedium;\r\n        }\r\n        &__extras{\r\n            & > li{\r\n            justify-content: space-around;\r\n            }\r\n        }\r\n        &__features{\r\n            & > li{\r\n                font-size: 1.4rem;\r\n                font-family: vars.$mainFontRegular\r\n            }\r\n        }\r\n        &__title{\r\n            font-size: 2rem;\r\n        }\r\n    }\r\n}\r\n","@use \"./vars\";\r\n@use \"./mixins\" as m;\r\n\r\n.scheme{\r\n    position: relative;\r\n    counter-reset: item 0;\r\n\r\n    &-container{\r\n        max-width: 45%;\r\n        &--horizontal {\r\n            width: 100%;\r\n            & > .scheme-container__title{\r\n                margin: 4rem 0 8rem;\r\n                @include m.mobile{\r\n             