x-width: vars.$mobile) {\r\n    .scheme-container {\r\n        max-width: 100%;\r\n    }\r\n\r\n    .scheme:not(.scheme--horizontal) {\r\n        --scheme-mobile-line-top: 6rem;\r\n        --scheme-mobile-line-bottom: 5.8rem;\r\n        width: 100%;\r\n        max-width: 100%;\r\n        padding: 0;\r\n\r\n        & > .scheme__item {\r\n            margin: 0 0 1rem 8rem;\r\n            min-width: 0;\r\n\r\n            &::before {\r\n                top: 50%;\r\n                left: 0;\r\n                translate: -135% -50%;\r\n                font-size: vars.$h5Size;\r\n            }\r\n        }\r\n\r\n        & > .scheme__item > .scheme__item-title {\r\n            font-size: vars.$pSize;\r\n            overflow-wrap: anywhere;\r\n\r\n            &::before {\r\n                top: 50%;\r\n                left: 0;\r\n                translate: -84% -50%;\r\n            }\r\n        }\r\n\r\n        & > .scheme__item > .scheme__item-text {\r\n            overflow-wrap: anywhere;\r\n        }\r\n\r\n        & > .scheme__line {\r\n            width: 3px;\r\n            height: auto;\r\n            left: 34px;\r\n            top: var(--scheme-mobile-line-top);\r\n            bottom: var(--scheme-mobile-line-bottom);\r\n            translate: 0 0;\r\n        }\r\n    }\r\n\r\n    .scheme-container--horizontal {\r\n        width: 100%;\r\n        max-width: 100%;\r\n        overflow-x: hidden;\r\n\r\n        & > .scheme-container__title {\r\n            margin: 3rem 0 3.6rem;\r\n        }\r\n    }\r\n\r\n    .scheme--horizontal {\r\n        display: block;\r\n        width: 100%;\r\n        max-width: 100%;\r\n        padding: 0;\r\n        & > .scheme__item {\r\n            margin: 0 0 1rem 8rem;\r\n            // padding: 2rem;\r\n            border: 1px solid vars.$borderColor;\r\n            border-radius: 1.5em;\r\n            background-color: vars.$white;\r\n            min-width: 0;\r\n            &::before {\r\n                top: 50%;\r\n                left: 0;\r\n                translate: -135% -50%;\r\n                // padding: 1.5rem 1.6rem;\r\n                font-size: vars.$h5Size;\r\n            }\r\n            & > .scheme__item-title {\r\n                font-size: vars.$pSize;\r\n                font-family: vars.$mainFontFamily;\r\n                font-weight: vars.$mainFontWeightMedium;\r\n                overflow-wrap: anywhere;\r\n\r\n                &::before {\r\n                    top: 50%;\r\n                    left: 0;\r\n                    rotate: 0deg;\r\n                    translate: -84% -50%;\r\n                }\r\n            }\r\n        }\r\n\r\n        & > .scheme__line {\r\n            width: 3px;\r\n            height: auto;\r\n            left: 34px;\r\n            top: 6rem;\r\n            bottom: 5.8rem;\r\n            translate: 0 0;\r\n\r\n            &--position1,\r\n            &--position2,\r\n            &--position3,\r\n            &--position4 {\r\n                width: 3px;\r\n                translate: 0 0;\r\n            }\r\n\r\n            &--position2{\r\n                height: 80%;\r\n                translate: 0 -10%;\r\n            }\r\n        }\r\n    }\r\n\r\n    .scheme:not(.scheme--horizontal).scheme--bank {\r\n        --scheme-mobile-line-top: 8rem;\r\n        --scheme-mobile-line-bottom: 8.3rem;\r\n    }\r\n}\r\n"]}